select v_1 as "l_shipmode", v_2 as "high_line_count", v_3 as "low_line_count" from (select v_4 as v_1, sum(case when (v_5 = '1-URGENT') or (v_5 = '2-HIGH') then 1 else 0 end) as v_2, sum(case when (v_5 <> '1-URGENT') and (v_5 <> '2-HIGH') then 1 else 0 end) as v_3 from (select * from (select * from (select "l_orderkey" as v_6, "l_partkey" as v_7, "l_suppkey" as v_8, "l_linenumber" as v_9, "l_quantity" as v_10, "l_extendedprice" as v_11, "l_discount" as v_12, "l_tax" as v_13, "l_returnflag" as v_14, "l_linestatus" as v_15, "l_shipdate" as v_16, "l_commitdate" as v_17, "l_receiptdate" as v_18, "l_shipinstruct" as v_19, "l_shipmode" as v_4, "l_comment" as v_20 from "lineitem") s where ((((v_17 < v_18) and (v_16 < v_17)) and (v_18 >= (date('1994-01-01', '+0 seconds')))) and (v_18 < (date('1994-01-01', '+1 year')))) and (v_4 in ('MAIL', 'SHIP'))) l inner join (select "o_orderkey" as v_21, "o_custkey" as v_22, "o_orderstatus" as v_23, "o_totalprice" as v_24, "o_orderdate" as v_25, "o_orderpriority" as v_5, "o_clerk" as v_26, "o_shippriority" as v_27, "o_comment" as v_28 from "orders") r on v_21 = v_6) s group by 1) s order by v_1
